// ═══════════════════════════════════════════════════════════════
// Extract Task Context + Collective Memory
// ═══════════════════════════════════════════════════════════════

const requestBody = $input.item.json.body;

// Task context from PM
const task_id = requestBody.task_id;
const task_title = requestBody.task_title;
const task_description = requestBody.task_description || '';
const task_phase = requestBody.task_phase;
const assignee = requestBody.assignee;
const context_questions = requestBody.context_questions || [];
const user_inputs = requestBody.user_inputs || {};
const depends_on = requestBody.depends_on || [];
const shared_memory = requestBody.shared_memory || {};
const project_id = shared_memory.project_id || requestBody.project_id;

// IMPORTANT: Load Collective Memory (last 20 entries)
// Milo needs to know what Luna (strategy) and previous Milo work said
let projectMemory = [];
try {
  const memoryQuery = await $supabase.query(
    `SELECT * FROM project_memory 
     WHERE project_id = $1 
     ORDER BY created_at DESC 
     LIMIT 20`,
    [project_id]
  );
  projectMemory = memoryQuery.rows || [];
} catch (error) {
  console.error('Failed to load project memory:', error);
}

// Load brand memory if exists
let brandMemory = {};
try {
  const brandQuery = await $supabase.query(
    `SELECT * FROM brand_memory WHERE project_id = $1`,
    [project_id]
  );
  brandMemory = brandQuery.rows[0] || {};
} catch (error) {
  console.error('Failed to load brand memory:', error);
}

return {
  json: {
    task_id,
    task_title,
    task_description,
    task_phase,
    assignee,
    context_questions,
    user_inputs,
    depends_on,
    shared_memory,
    project_id,
    project_memory: projectMemory,
    brand_memory: brandMemory,
  }
};

// ═══════════════════════════════════════════════════════════════
// Parse Milo Response & Extract Write-Back Commands
// ═══════════════════════════════════════════════════════════════

const miloResponse = $input.item.json;
const responseText = miloResponse.text || miloResponse.content || '';

// Extract COMMAND blocks (pattern: COMMAND: XXX)
const commandPattern = /COMMAND:\s*([A-Z_]+)[\s\S]*?REASON:\s*([^\n]+)[\s\S]*?PAYLOAD:\s*(\{[\s\S]*?\})/g;
const commands = [];

let match;
while ((match = commandPattern.exec(responseText)) !== null) {
  const [_, command, reason, payloadStr] = match;
  try {
    const payload = JSON.parse(payloadStr);
    commands.push({
      command,
      reason,
      payload
    });
  } catch (e) {
    console.error('Failed to parse command payload:', e, payloadStr);
  }
}

return {
  json: {
    agent_response: {
      message: responseText.split('COMMAND:')[0].trim(),
      agent_used: 'milo',
      commands,
      raw_response: responseText
    },
    task_context: $('Extract Context + Memory').item.json
  }
};

// ═══════════════════════════════════════════════════════════════
// Execute Write-Back Commands to Supabase
// ═══════════════════════════════════════════════════════════════

const { commands } = $input.item.json.agent_response;
const taskContext = $input.item.json.task_context;
const project_id = taskContext.project_id;

for (const cmd of commands) {
  try {
    switch (cmd.command) {
      case 'ADD_FILE':
        // Store generated creative assets
        await $supabase.query(
          `INSERT INTO project_files 
           (project_id, file_type, file_name, file_base64, metadata, created_by) 
           VALUES ($1, $2, $3, $4, $5, $6)`,
          [
            project_id,
            cmd.payload.file_type,
            cmd.payload.file_name,
            cmd.payload.file_base64,
            JSON.stringify(cmd.payload.metadata || {}),
            'milo'
          ]
        );
        console.log(`✅ File added: ${cmd.payload.file_name}`);
        break;

      case 'UPDATE_TASK_STATUS':
        // Mark task as done
        await $supabase.query(
          `UPDATE tasks 
           SET status = $1, completion_notes = $2, completed_at = NOW(), updated_at = NOW() 
           WHERE id = $3`,
          [
            cmd.payload.status,
            cmd.payload.completion_notes,
            cmd.payload.task_id
          ]
        );
        console.log(`✅ Task ${cmd.payload.task_id} updated to ${cmd.payload.status}`);
        break;

      case 'MEMORY_WRITE':
        // Write to collective memory
        await $supabase.query(
          `INSERT INTO project_memory 
           (project_id, agent_id, task_id, action, summary, key_findings, deliverables, recommendations) 
           VALUES ($1, $2, $3, $4, $5, $6, $7, $8)`,
          [
            project_id,
            'milo',
            taskContext.task_id,
            cmd.payload.action || 'CREATIVE_WORK_COMPLETED',
            cmd.payload.summary || cmd.payload.content,
            JSON.stringify(cmd.payload.key_findings || []),
            JSON.stringify(cmd.payload.deliverables || []),
            JSON.stringify(cmd.payload.recommendations || [])
          ]
        );
        console.log(`✅ Memory written to collective memory`);
        break;

      case 'NOTIFY_USER':
        // Send notification (Supabase Realtime or email)
        await $supabase.query(
          `INSERT INTO notifications 
           (project_id, type, title, message, metadata, created_by) 
           VALUES ($1, $2, $3, $4, $5, $6)`,
          [
            project_id,
            'task_update',
            'Milo a terminé',
            cmd.payload.message,
            JSON.stringify({ attachments: cmd.payload.attachments || [] }),
            'milo'
          ]
        );
        console.log(`✅ User notified`);
        break;

      case 'REQUEST_TASK':
        // Create follow-up task
        await $supabase.query(
          `INSERT INTO tasks 
           (project_id, title, description, assignee, priority, depends_on, status, phase) 
           VALUES ($1, $2, $3, $4, $5, $6, $7, $8)`,
          [
            project_id,
            cmd.payload.task_title,
            cmd.payload.task_description,
            cmd.payload.assignee || 'milo',
            cmd.payload.priority || 'medium',
            JSON.stringify(cmd.payload.depends_on || [taskContext.task_id]),
            'todo',
            cmd.payload.phase || 'Production'
          ]
        );
        console.log(`✅ New task created: ${cmd.payload.task_title}`);
        break;

      default:
        console.warn(`⚠️ Unknown command: ${cmd.command}`);
    }
  } catch (error) {
    console.error(`❌ Error executing command ${cmd.command}:`, error);
  }
}

return {
  json: {
    success: true,
    commands_executed: commands.length,
    agent_response: $input.item.json.agent_response
  }
};
